#define THREADS 256

inline int mirror_index(int d, int size)
{
    if (size <= 1) return 0;
    while (d < 0 || d >= size) {
        if (d < 0) {
            d = -d;
        }
        if (d >= size) {
            d = 2 * size - 2 - d;
        }
    }
    return d;
}

inline int src_at(__global const int *src, int width, int height, int x, int y)
{
    int mx = mirror_index(x, width);
    int my = mirror_index(y, height);
    return src[my * width + mx];
}

inline int tmp_at(__global const int *tmp, int width, int height, int x, int y)
{
    int my = mirror_index(y, height);
    return tmp[my * width + x];
}

inline int fdwt53_odd_horizontal(__global const int *src, int width, int height, int xodd, int y)
{
    int c = src_at(src, width, height, xodd, y);
    int p = src_at(src, width, height, xodd - 1, y);
    int n = src_at(src, width, height, xodd + 1, y);
    return c - (p + n) / 2;
}

inline int fdwt53_even_horizontal(__global const int *src, int width, int height, int xeven, int y)
{
    int c = src_at(src, width, height, xeven, y);
    int p = fdwt53_odd_horizontal(src, width, height, xeven - 1, y);
    int n = fdwt53_odd_horizontal(src, width, height, xeven + 1, y);
    return c + (p + n + 2) / 4;
}

inline int fdwt53_odd_vertical(__global const int *tmp, int width, int height, int x, int yodd)
{
    int c = tmp_at(tmp, width, height, x, yodd);
    int p = tmp_at(tmp, width, height, x, yodd - 1);
    int n = tmp_at(tmp, width, height, x, yodd + 1);
    return c - (p + n) / 2;
}

inline int fdwt53_even_vertical(__global const int *tmp, int width, int height, int x, int yeven)
{
    int c = tmp_at(tmp, width, height, x, yeven);
    int p = fdwt53_odd_vertical(tmp, width, height, x, yeven - 1);
    int n = fdwt53_odd_vertical(tmp, width, height, x, yeven + 1);
    return c + (p + n + 2) / 4;
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    const int pixels)
{
    int gid = (int)get_global_id(0);
    int gsz = (int)get_global_size(0);

    for (int i = gid; i < pixels; i += gsz) {
        int base = 3 * i;
        d_r[i] = (int)d_src[base + 0] - 128;
        d_g[i] = (int)d_src[base + 1] - 128;
        d_b[i] = (int)d_src[base + 2] - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   const int pixels)
{
    int gid = (int)get_global_id(0);
    int gsz = (int)get_global_size(0);

    for (int i = gid; i < pixels; i += gsz) {
        d_c[i] = (int)d_src[i] - 128;
    }
}

__kernel void cl_fdwt53Kernel(__global int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int winSteps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    if (get_global_id(0) != 0 || get_global_id(1) != 0) {
        return;
    }

    const int lowX = (sizeX + 1) >> 1;
    const int highX = sizeX >> 1;
    const int lowY = (sizeY + 1) >> 1;
    const int highY = sizeY >> 1;


    for (int y = 0; y < sizeY; ++y) {
        for (int k = 0; k < lowX; ++k) {
            int x = k << 1;
            output[y * sizeX + k] = fdwt53_even_horizontal(input, sizeX, sizeY, x, y);
        }
        for (int k = 0; k < highX; ++k) {
            int x = (k << 1) + 1;
            output[y * sizeX + lowX + k] = fdwt53_odd_horizontal(input, sizeX, sizeY, x, y);
        }
    }


    int llOffset = 0;
    int hlOffset = lowX * lowY;
    int lhOffset = hlOffset + highX * lowY;
    int hhOffset = lhOffset + lowX * highY;


    for (int x = 0; x < lowX; ++x) {
        for (int k = 0; k < lowY; ++k) {
            int y = k << 1;
            input[llOffset + k * lowX + x] = fdwt53_even_vertical(output, sizeX, sizeY, x, y);
        }
        for (int k = 0; k < highY; ++k) {
            int y = (k << 1) + 1;
            input[lhOffset + k * lowX + x] = fdwt53_odd_vertical(output, sizeX, sizeY, x, y);
        }
    }


    for (int x = 0; x < highX; ++x) {
        int tx = lowX + x;
        for (int k = 0; k < lowY; ++k) {
            int y = k << 1;
            input[hlOffset + k * highX + x] = fdwt53_even_vertical(output, sizeX, sizeY, tx, y);
        }
        for (int k = 0; k < highY; ++k) {
            int y = (k << 1) + 1;
            input[hhOffset + k * highX + x] = fdwt53_odd_vertical(output, sizeX, sizeY, tx, y);
        }
    }


    int total = sizeX * sizeY;
    for (int i = 0; i < total; ++i) {
        output[i] = input[i];
    }
}
